import React, { useState, useEffect } from "react";
import { Sparkline } from "./Sparkline";

function parseSets(ex) {
  if (ex.sets && ex.reps) return { sets: parseInt(ex.sets, 10) || 3, reps: ex.reps };
  const raw = ex.sets || ex.reps || "";
  const m = String(raw).match(/^(\d+)[xX×](.+)$/);
  if (m) return { sets: parseInt(m[1], 10), reps: m[2] };
  return { sets: 3, reps: raw || "—" };
}

function SetRow({ setIdx, defaultReps, log, onChange }) {
  const [weight, setWeight] = useState(log?.weight ?? "");
  const [reps, setReps] = useState(log?.reps ?? "");

  useEffect(() => {
    setWeight(log?.weight ?? "");
    setReps(log?.reps ?? "");
  }, [log]);

  const commit = () => {
    if (weight !== "" || reps !== "") {
      onChange({
        weight: weight !== "" ? parseFloat(weight) : null,
        reps: reps !== "" ? reps : null,
        date: new Date().toISOString().split("T")[0],
      });
    }
  };
  const done = log?.weight != null && log.weight !== "";

  return (
    <div
      className="flex items-center gap-2.5 py-2.5"
      style={{ borderBottom: "1px solid rgba(255,255,255,0.04)" }}
    >
      {/* Numéro */}
      <div
        style={{
          width: 28, height: 28, borderRadius: 6,
          background: "#1e1e1e",
          display: "flex", alignItems: "center", justifyContent: "center",
          flexShrink: 0
        }}
      >
        <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5, color: done ? "#f97316" : "#555" }}>
          {setIdx + 1}
        </span>
      </div>

      {/* Charge */}
      <input
        type="number" inputMode="decimal"
        placeholder="kg"
        value={weight}
        onChange={(e) => setWeight(e.target.value)}
        onBlur={commit}
        style={{
          flex: 1,
          padding: "8px 8px",
          background: weight !== "" ? "rgba(249,115,22,0.06)" : "#1a1a1a",
          border: weight !== "" ? "1.5px solid rgba(249,115,22,0.35)" : "1.5px solid rgba(255,255,255,0.08)",
          borderRadius: 7,
          color: "#f5f5f5",
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: 14, fontWeight: 500,
          outline: "none",
          textAlign: "center",
          transition: "border-color 0.15s",
        }}
      />

      <span style={{ color: "#444", fontSize: 12, flexShrink: 0 }}>×</span>

      {/* Reps */}
      <input
        type="text" inputMode="numeric"
        placeholder={defaultReps || "reps"}
        value={reps}
        onChange={(e) => setReps(e.target.value)}
        onBlur={commit}
        style={{
          flex: 1,
          padding: "8px 8px",
          background: reps !== "" ? "rgba(249,115,22,0.06)" : "#1a1a1a",
          border: reps !== "" ? "1.5px solid rgba(249,115,22,0.35)" : "1.5px solid rgba(255,255,255,0.08)",
          borderRadius: 7,
          color: "#f5f5f5",
          fontFamily: "'JetBrains Mono', monospace",
          fontSize: 14, fontWeight: 500,
          outline: "none",
          textAlign: "center",
          transition: "border-color 0.15s",
        }}
      />

      {/* Coche */}
      <div
        style={{
          width: 22, height: 22, borderRadius: "50%", flexShrink: 0,
          display: "flex", alignItems: "center", justifyContent: "center",
          border: done ? "2px solid #f97316" : "2px solid #2a2a2a",
          background: done ? "#f97316" : "transparent",
          transition: "all 0.2s",
        }}
      >
        {done && (
          <svg viewBox="0 0 24 24" fill="none" style={{ width: 12, height: 12 }} stroke="#fff" strokeWidth="3">
            <polyline points="20 6 9 17 4 12" />
          </svg>
        )}
      </div>
    </div>
  );
}

export function ExerciseCard({ ex, weekIdx, sessionIdx, exIdx, globalIndex, getHistory, getLatest, saveLog, getDelta }) {
  const [expanded, setExpanded] = useState(false);
  const [saved, setSaved] = useState(false);
  const { sets, reps } = parseSets(ex);
  const numSets = sets || 3;

  const history = getHistory(weekIdx, sessionIdx, exIdx);
  const latest = getLatest(weekIdx, sessionIdx, exIdx);
  const delta = getDelta(weekIdx, sessionIdx, exIdx);

  const [inputWeight, setInputWeight] = useState(latest ? String(latest.weight) : "");
  const [inputReps, setInputReps] = useState(latest ? String(latest.reps || reps || "") : "");

  const completedSets = Array.from({ length: numSets }, (_, i) => {
    // Simplified: if there's any log for this exercise, count it
    return history.length > 0;
  }).filter(Boolean).length;

  const allDone = history.length > 0;

  const handleSave = () => {
    if (!inputWeight) return;
    saveLog(weekIdx, sessionIdx, exIdx, inputWeight, inputReps);
    setSaved(true);
    setTimeout(() => setSaved(false), 1800);
  };

  const deltaPos = delta !== null && delta > 0;
  const deltaNeg = delta !== null && delta < 0;

  return (
    <div
      className="ex-card"
      style={{
        borderColor: allDone ? "rgba(249,115,22,0.25)" : undefined,
        borderLeft: ex.group ? "3px solid #f97316" : allDone ? "3px solid rgba(249,115,22,0.5)" : undefined,
      }}
    >
      {ex.group && (
        <div className="ex-superset-badge">
          {ex.groupType || "Superset"} {ex.group}
        </div>
      )}

      {/* Header */}
      <button
        onClick={() => setExpanded((v) => !v)}
        style={{ display: "flex", alignItems: "flex-start", gap: 12, textAlign: "left", background: "none", border: "none", cursor: "pointer", width: "100%", padding: 0 }}
      >
        <div className="ex-num" style={{ background: allDone ? "rgba(249,115,22,0.15)" : undefined }}>
          <span style={{ color: allDone ? "#f97316" : undefined }}>
            {String(globalIndex + 1).padStart(2, "0")}
          </span>
        </div>

        <div className="ex-title-block">
          <div className="ex-name">{ex.name}</div>
          <div className="ex-meta">
            {reps && reps !== "—" && (
              <span className="ex-chip ex-chip-sets">{numSets} × {reps}</span>
            )}
            {ex.tempo && ex.tempo !== "—" && (
              <span className="ex-chip ex-chip-tempo">{ex.tempo}</span>
            )}
            {ex.rir != null && ex.rir !== "—" && (
              <span className="ex-chip ex-chip-rir">RIR {ex.rir}</span>
            )}
            {ex.rest && ex.rest !== "—" && (
              <span className="ex-chip ex-chip-rest">⏱ {ex.rest}</span>
            )}
          </div>
        </div>

        <div style={{ display: "flex", flexDirection: "column", alignItems: "flex-end", gap: 4, flexShrink: 0 }}>
          {history.length > 0 && (
            <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 10.5, color: "#f97316" }}>
              ✓
            </span>
          )}
          <svg
            viewBox="0 0 24 24" fill="none"
            style={{ width: 14, height: 14, color: "#555", transform: expanded ? "rotate(180deg)" : "rotate(0deg)", transition: "transform 0.2s" }}
            stroke="currentColor" strokeWidth="2"
          >
            <polyline points="6 9 12 15 18 9" />
          </svg>
        </div>
      </button>

      {/* Quick log */}
      <div className="ex-log-row">
        <div className="ex-input-group">
          <label className="ex-input-label">Charge</label>
          <div className="ex-input-wrap">
            <input
              type="number" inputMode="decimal"
              className="ex-input"
              placeholder={latest ? String(latest.weight) : "0"}
              value={inputWeight}
              onChange={(e) => setInputWeight(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSave()}
            />
            <span className="ex-unit">kg</span>
          </div>
        </div>
        <div className="ex-input-group">
          <label className="ex-input-label">Reps</label>
          <div className="ex-input-wrap">
            <input
              type="text"
              className="ex-input"
              placeholder={reps || "—"}
              value={inputReps}
              onChange={(e) => setInputReps(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && handleSave()}
            />
          </div>
        </div>
        <button
          className={`ex-save-btn ${saved ? "saved" : ""}`}
          onClick={handleSave}
        >
          {saved ? (
            <svg viewBox="0 0 20 20" fill="none">
              <polyline points="4,10 8,14 16,6" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          ) : (
            <svg viewBox="0 0 20 20" fill="none">
              <line x1="10" y1="4" x2="10" y2="16" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
              <line x1="4" y1="10" x2="16" y2="10" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
            </svg>
          )}
        </button>
      </div>

      {/* Progression */}
      {(latest || history.length > 0) && (
        <div className="ex-progress-row">
          <div className="ex-last">
            <span className="ex-last-label">Dernier</span>
            <span className="ex-last-val">{latest?.weight} kg</span>
            {delta !== null && (
              <span className={`ex-delta ${deltaPos ? "pos" : deltaNeg ? "neg" : "neu"}`}>
                {deltaPos ? "+" : ""}{delta !== 0 ? delta.toFixed(1) + " kg" : "="}
              </span>
            )}
          </div>
          {history.length >= 2 && (
            <div className="ex-spark">
              <Sparkline data={history} width={68} height={22} />
            </div>
          )}
          <button
            className="ex-history-toggle"
            onClick={() => setExpanded((v) => !v)}
          >
            {expanded ? "Fermer" : `${history.length} séance${history.length > 1 ? "s" : ""}`}
          </button>
        </div>
      )}

      {/* Historique */}
      {expanded && history.length > 0 && (
        <div className="ex-history">
          <p style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: 9, letterSpacing: "1.5px", textTransform: "uppercase", color: "#555", marginBottom: 4 }}>
            Historique
          </p>
          {[...history].reverse().slice(0, 8).map((entry, i) => (
            <div key={i} className="ex-history-row">
              <span className="ex-history-date">
                {new Date(entry.date).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}
              </span>
              <span className="ex-history-weight">{entry.weight} kg</span>
              {entry.reps && <span className="ex-history-reps">× {entry.reps}</span>}
            </div>
          ))}
        </div>
      )}

      {/* Lien vidéo */}
      {ex.vidUrl && (
        <a
          href={ex.vidUrl}
          target="_blank"
          rel="noreferrer"
          style={{
            display: "flex", alignItems: "center", gap: 7,
            fontSize: 11.5, color: "#f97316", textDecoration: "none",
            fontWeight: 500,
          }}
        >
          <svg viewBox="0 0 20 20" fill="none" style={{ width: 15, height: 15, flexShrink: 0 }}>
            <circle cx="10" cy="10" r="8" stroke="#f97316" strokeWidth="1.5"/>
            <polygon points="8,7 14,10 8,13" fill="#f97316"/>
          </svg>
          Voir la vidéo
        </a>
      )}
    </div>
  );
}
